def class_section(class_key, heading, intro, cta_heading, cta_text, items):
    FAQ_DATA[class_key] = section(heading, intro, cta_heading, cta_text, "Start Learning", "class_detail_primary", items)

class_section("class_9", "CBSE Class 9 FAQs", "Class 9 is an important step in a student's academic journey, introducing more advanced concepts and greater independence in learning. Building strong fundamentals at this stage helps students prepare for future classes with confidence.", "Build a strong foundation for future success.", "Explore AI-powered notes, structured learning, chapter-wise practice, mock tests, and personalised learning insights through the Genelis Learning System—designed to help you build confidence from Class 9 onwards.", [
    ("Is Genelis suitable for CBSE Class 9 students?", "Yes. Genelis is designed to support CBSE Class 9 students by providing AI-powered notes, structured chapter-wise learning, practice questions, mock tests, personalised learning insights, and performance analytics. Whether you're beginning a new chapter or revising for school examinations, the platform helps make learning more organised, engaging, and effective throughout the academic year."),
    ("Does Genelis cover the complete CBSE Class 9 syllabus?", "Genelis is designed around the latest available CBSE curriculum and NCERT textbooks for Class 9. Learning resources are organised chapter-wise across supported subjects, making it easier for students to study systematically, revise concepts, and monitor their progress. As official curriculum updates become available, the platform aims to reflect those changes to ensure learning remains accurate and relevant."),
    ("Can I generate AI Notes for every Class 9 chapter?", "Students can generate AI-powered notes for supported Class 9 chapters across available subjects. These notes summarise important concepts, definitions, formulas, and key learning points in a clear and structured format. They are designed to complement classroom teaching and NCERT textbooks while helping students revise more efficiently and understand concepts with greater clarity."),
    ("How does Genelis help students build strong study habits?", "Developing consistent study habits is one of the most valuable skills students can build during Class 9. The Genelis Learning System encourages students to learn concepts, practise regularly, test their understanding, analyse their progress, improve weaker areas, and reinforce learning through revision. Following this structured approach helps students stay organised while building confidence and discipline throughout the academic year."),
    ("How do Class 9 mock tests work?", "Genelis provides chapter-wise and subject-wise mock tests that allow students to evaluate their understanding as they progress through the syllabus. After each attempt, students receive performance insights that highlight strengths, identify weaker concepts, and recommend areas for further revision. Regular practice helps students become more confident while preparing for school examinations."),
    ("How does Genelis identify my weak areas?", "Genelis AI analyses chapter-wise practice, mock test performance, and learning activity to identify concepts that may require additional attention. Instead of focusing only on marks, the platform looks for recurring mistakes and learning patterns, helping students revise more effectively and strengthen concepts before moving on to new topics."),
    ("Can Genelis help me prepare for Class 10?", "Yes. Class 9 provides the academic foundation for many topics that students will encounter in Class 10. By encouraging conceptual understanding, regular revision, and consistent practice, Genelis helps students develop learning habits and confidence that support a smoother transition into the next stage of their academic journey."),
    ("What is the Wrong Question Notebook and how does it help?", "The Wrong Question Notebook automatically stores questions answered incorrectly during practice sessions and mock tests. Instead of repeating the entire syllabus, students can revisit previous mistakes, understand the correct approach, and strengthen concepts that need additional practice. This targeted revision helps improve understanding while reducing repeated errors over time."),
    ("Can I study at my own pace with Genelis?", "Yes. Every student learns differently, and Genelis is designed to support individual learning styles. Students can study chapter-wise, revisit difficult concepts whenever needed, practise at their own pace, and receive personalised recommendations from Genelis AI based on their learning progress and performance."),
    ("How does the Genelis Learning System help Class 9 students?", "The Genelis Learning System combines AI-powered notes, structured learning, chapter-wise practice, mock tests, performance analytics, personalised learning recommendations, and continuous revision into one connected experience. By helping students understand concepts, identify weaker areas, revisit previous mistakes, and improve consistently, the platform encourages stronger learning habits that support long-term academic success."),
])

class_section("class_10", "CBSE Class 10 FAQs", "Class 10 is an important milestone in every student's academic journey. Whether you're preparing for school assessments or the CBSE Board Examination, having the right study resources and a structured learning approach can make a significant difference.", "Ready to prepare for CBSE Class 10 with confidence?", "Explore AI-powered notes, structured revision, mock tests, personalised learning insights, and the Genelis Learning System—all designed to help you study smarter throughout the academic year.", [
    ("Is Genelis suitable for CBSE Class 10 students?", "Yes. Genelis is specifically designed to support CBSE Class 10 students through every stage of their preparation. Whether you're learning a chapter for the first time, revising before an exam, or preparing for the board examinations, the platform provides AI-powered notes, structured practice, mock tests, personalised learning insights, and performance analysis to help you study with greater clarity and consistency throughout the academic year."),
    ("Does Genelis cover the complete CBSE Class 10 syllabus?", "Genelis is designed around the latest available CBSE curriculum and NCERT textbooks for Class 10. Learning resources are organised chapter-wise across supported subjects, making it easier to study individual topics, revise important concepts, and prepare systematically. As official syllabus updates become available, the platform aims to keep its educational content aligned with the latest academic requirements."),
    ("Can I generate AI Notes for every Class 10 chapter?", "Students can generate AI-powered notes for supported Class 10 chapters across available subjects. These notes summarise important concepts, definitions, formulas, examples, and revision points in a structured format that complements classroom teaching and NCERT textbooks. They are designed to make revision more efficient while encouraging students to build a deeper conceptual understanding."),
    ("How do Class 10 mock tests work?", "Genelis provides chapter-wise and subject-wise mock tests designed to reflect the style and learning objectives of the CBSE curriculum. Students can attempt mock tests to evaluate their understanding, identify areas that need improvement, and monitor their progress over time. Detailed performance insights help students revise more strategically instead of relying only on overall scores."),
    ("Can Genelis help improve my board exam preparation?", "Genelis is designed to support long-term preparation rather than last-minute learning. Through AI-generated notes, structured revision, regular practice, mock tests, personalised recommendations, and continuous performance analysis, students can prepare more consistently throughout the year. While examination results always depend on individual effort and understanding, the platform helps students build stronger preparation habits and greater confidence before the board examinations."),
    ("How does Genelis identify my weak areas?", "Genelis AI analyses learning activity, practice sessions, and mock test performance to identify concepts that may require additional attention. Instead of focusing only on marks, the platform looks for recurring mistakes and learning patterns to recommend more focused revision. This allows students to spend more time improving concepts that have the greatest impact on their overall preparation."),
    ("Can I revise chapter-wise before my exams?", "Yes. Every supported chapter is organised individually so students can revise topics according to their own study plan. AI Notes, chapter-wise practice, mock tests, and performance insights work together to help students strengthen one concept at a time while maintaining steady progress across the entire syllabus."),
    ("Can I prepare for CBSE Class 10 without coaching?", "Every student learns differently, and there is no single preparation method that works for everyone. Genelis is designed to support independent learning by providing structured resources, AI-powered guidance, chapter-wise practice, and continuous performance insights. Many students may find these tools helpful for self-study, while others may choose to use Genelis alongside classroom teaching or coaching depending on their individual learning needs."),
    ("Does Genelis include previous-year question practice?", "Genelis aims to help students practise questions that reflect the concepts and learning outcomes expected under the CBSE curriculum. Where available, students may also benefit from additional question practice designed to strengthen conceptual understanding and exam readiness. The platform continues to expand its learning resources as new educational content is introduced."),
    ("How does the Genelis Learning System help Class 10 students?", "The Genelis Learning System combines learning, practice, testing, analysis, improvement, and revision into one connected experience. Instead of switching between multiple resources, students can generate AI Notes, practise chapter-wise questions, attempt mock tests, review performance analytics, identify weaker areas, revisit mistakes through the Wrong Question Notebook, and receive personalised learning recommendations within a single platform. This structured approach helps students study more efficiently while developing stronger understanding and greater confidence throughout their Class 10 journey."),
])

class_section("class_11", "CBSE Class 11 FAQs", "Class 11 marks the beginning of advanced academic learning, where building strong concepts becomes more important than memorising answers. Whether you're adjusting to a new syllabus, preparing for school examinations, or laying the foundation for future board and competitive exams, Genelis helps you learn with greater structure, clarity, and confidence.", "Build stronger concepts from the very beginning.", "Discover how the Genelis Learning System combines AI-powered notes, structured practice, mock tests, and personalised learning insights to help you succeed throughout Class 11 and beyond.", [
    ("Is Genelis suitable for CBSE Class 11 students?", "Yes. Genelis is designed to support CBSE Class 11 students through AI-powered notes, structured chapter-wise learning, mock tests, personalised learning insights, and performance analytics. Since Class 11 introduces more advanced concepts across subjects, the platform focuses on helping students develop strong fundamentals while encouraging consistent study habits throughout the academic year."),
    ("Does Genelis cover the complete CBSE Class 11 syllabus?", "Genelis is designed around the latest available CBSE curriculum and NCERT textbooks for Class 11. Learning resources are organised chapter-wise across supported subjects, allowing students to study systematically, revise important concepts, and monitor their progress as they complete the syllabus. The platform continues to evolve alongside official curriculum updates wherever applicable."),
    ("Can I generate AI Notes for every Class 11 chapter?", "Students can generate AI-powered notes for supported Class 11 chapters across available subjects. These notes highlight important concepts, definitions, formulas, and key learning points in a structured format that supports classroom teaching and NCERT textbooks. They are designed to simplify revision while helping students understand concepts rather than simply memorising information."),
    ("How does Genelis help build strong concepts in Class 11?", "Class 11 introduces topics that form the foundation for Class 12 and many competitive examinations. The Genelis Learning System encourages students to first understand concepts through AI Notes and structured explanations before reinforcing learning through practice questions, mock tests, personalised recommendations, and continuous revision. This approach helps students develop confidence by strengthening conceptual understanding step by step."),
    ("How do Class 11 mock tests work?", "Genelis provides chapter-wise and subject-wise mock tests that allow students to regularly assess their understanding throughout the year. After every attempt, students receive detailed performance insights that help identify strengths, recognise weaker concepts, and plan more focused revision. This continuous evaluation supports steady academic improvement rather than relying only on end-of-term examinations."),
    ("How does Genelis identify my weak areas?", "Genelis AI analyses learning activity, practice sessions, and mock test performance to identify concepts that require additional attention. Instead of focusing only on scores, the platform identifies recurring mistakes and learning patterns to recommend areas where additional study may be beneficial, helping students improve more efficiently over time."),
    ("Can Genelis support preparation for future competitive exams?", "While Genelis is primarily designed for CBSE Class 11 learning, developing strong conceptual understanding during this stage also benefits students preparing for future competitive examinations. By helping students build solid fundamentals, maintain consistent revision, and identify weaker topics early, the platform supports long-term academic preparation alongside regular school studies."),
    ("What is the Wrong Question Notebook and how does it help?", "The Wrong Question Notebook automatically stores questions answered incorrectly during practice sessions and mock tests. Instead of repeating the entire syllabus, students can revisit previous mistakes, understand the correct approach, and strengthen concepts that need additional attention. This focused revision helps reduce repeated errors while improving long-term retention."),
    ("Can I study at my own pace with Genelis?", "Yes. Every student learns differently. Genelis allows students to progress according to their own learning pace while using AI-powered notes, chapter-wise practice, mock tests, and personalised recommendations to support consistent improvement. Students can spend additional time on difficult topics while continuing to monitor their overall progress across subjects."),
    ("How does the Genelis Learning System help Class 11 students?", "The Genelis Learning System combines learning, practice, testing, analysis, improvement, and revision into one connected experience. Students can generate AI Notes, practise chapter-wise questions, attempt mock tests, analyse their performance, identify weaker concepts, revisit mistakes through the Wrong Question Notebook, and receive personalised learning recommendations—all within a single platform. This structured approach helps students build the strong conceptual foundation needed for future academic success."),
])

class_section("class_12", "CBSE Class 12 FAQs", "Class 12 is one of the most important years in a student's academic journey. Along with preparing for the CBSE Board Examination, many students are also balancing entrance exam preparation and planning their next academic step.", "Ready to prepare for CBSE Class 12 with confidence?", "Explore AI-powered notes, chapter-wise practice, structured revision, mock tests, and personalised learning insights through the Genelis Learning System—all designed to help you study smarter throughout your Class 12 journey.", [
    ("Is Genelis suitable for CBSE Class 12 students?", "Yes. Genelis is designed to help CBSE Class 12 students prepare with greater confidence through structured learning, AI-powered notes, chapter-wise practice, mock tests, personalised learning insights, and performance analytics. Whether you're revising a single chapter or preparing for the board examinations, the platform helps organise your preparation while encouraging consistent learning throughout the academic year."),
    ("Does Genelis cover the complete CBSE Class 12 syllabus?", "Genelis is designed around the latest available CBSE curriculum and NCERT textbooks for Class 12. Learning resources are organised chapter-wise across supported subjects, allowing students to study systematically, revise concepts efficiently, and prepare according to the prescribed syllabus. As official curriculum updates become available, the platform aims to reflect those changes to keep learning relevant and aligned with current academic requirements."),
    ("Can I generate AI Notes for every Class 12 chapter?", "Students can generate AI-powered notes for supported Class 12 chapters across available subjects. These notes summarise important concepts, formulas, definitions, diagrams where applicable, and revision points in a structured format that complements classroom teaching and NCERT textbooks. They are intended to simplify revision while helping students strengthen conceptual understanding before examinations."),
    ("How do Class 12 mock tests work?", "Genelis provides chapter-wise and subject-wise mock tests designed to help students evaluate their preparation throughout the year. After every attempt, students receive performance insights that highlight strengths, identify weaker concepts, and support more focused revision. Regular mock testing also helps students become more familiar with exam-style questions and improve confidence before the board examinations."),
    ("Can Genelis help me prepare for both board exams and competitive exams?", "Genelis is primarily designed to support CBSE Class 12 learning and board examination preparation. Because strong conceptual understanding is essential for many competitive examinations, the platform also helps students build a solid academic foundation through structured learning, continuous practice, and personalised revision. Students preparing for specific competitive exams should continue to use resources designed for those examinations alongside their board preparation."),
    ("How does Genelis identify my weak areas?", "Genelis AI analyses learning activity, chapter-wise practice, and mock test performance to identify concepts that require additional attention. Rather than focusing only on overall marks, the platform looks for recurring mistakes and learning patterns, helping students prioritise revision where it can have the greatest impact on their overall preparation."),
    ("Can I revise chapter-wise before the board examinations?", "Yes. Every supported chapter is organised individually, allowing students to revise according to their own study schedule. AI Notes, chapter-wise practice, mock tests, performance insights, and personalised recommendations work together to help students strengthen concepts systematically while ensuring balanced preparation across the entire syllabus."),
    ("How does the Wrong Question Notebook help Class 12 students?", "The Wrong Question Notebook automatically collects questions answered incorrectly during practice sessions and mock tests. Instead of revising the entire syllabus repeatedly, students can focus specifically on previous mistakes, understand why the correct answer is right, and revisit concepts that require further practice. This targeted revision approach helps improve accuracy and long-term retention."),
    ("Can Genelis support self-study during Class 12?", "Yes. Many students prefer to study independently or supplement classroom learning with additional practice. Genelis supports self-study by bringing AI-powered notes, structured revision, mock tests, personalised learning insights, and progress tracking into one connected platform. Students can learn at their own pace while receiving guidance on what to revise next based on their performance."),
    ("How does the Genelis Learning System help Class 12 students?", "The Genelis Learning System provides a structured approach to preparation by combining conceptual learning, chapter-wise practice, mock tests, performance analytics, personalised recommendations, and continuous revision into one connected experience. Features such as AI Notes, Weak Area Detection, Wrong Question Notebook, and Reattempt Mocks help students strengthen understanding, improve consistency, and prepare more confidently for their board examinations."),
])


def build_faq_schema(faq):
    return {
        "@context": "https://schema.org",
        "@type": "FAQPage",
        "mainEntity": [
            {
                "@type": "Question",
                "name": item["question"],
                "acceptedAnswer": {
                    "@type": "Answer",
                    "text": item["answer"],
                },
            }
            for item in faq["items"]
        ],
    }
